# Option A: pgvector (PostgreSQL extension) — good for existing Postgres stacks
CREATE EXTENSION IF NOT EXISTS vector;

CREATE TABLE kb_chunks (
    id         BIGSERIAL PRIMARY KEY,
    doc_id     TEXT NOT NULL,
    chunk_idx  INT  NOT NULL,
    content    TEXT NOT NULL,
    embedding  vector(1536),
    metadata   JSONB DEFAULT '{}'
);

CREATE INDEX ON kb_chunks USING hnsw (embedding vector_cosine_ops);

# Option C: Qdrant (managed / local Docker)
from qdrant_client import QdrantClient
from qdrant_client.models import Distance, VectorParams, PointStruct
import uuid

qclient = QdrantClient(":memory:")   # replace with host= for persistent

COLLECTION = "knowledge_base"

def ensure_collection(dim: int = 1536) -> None:
    if COLLECTION not in [c.name for c in qclient.get_collections().collections]:
        qclient.create_collection(
            COLLECTION,
            vectors_config=VectorParams(size=dim, distance=Distance.COSINE),
        )

def upsert_to_qdrant(chunks: list[Chunk], embeddings: list[list[float]]) -> None:
    ensure_collection(len(embeddings[0]))
    points = [
        PointStruct(
            id=str(uuid.uuid4()),
            vector=emb,
            payload={"text": c.text, "doc_id": c.doc_id, **c.metadata},
        )
        for c, emb in zip(chunks, embeddings)
    ]
    qclient.upsert(collection_name=COLLECTION, points=points)

import hashlib, pathlib, json

STATE_FILE = "kb_state.json"

def file_hash(path: str) -> str:
    return hashlib.sha256(pathlib.Path(path).read_bytes()).hexdigest()

def incremental_ingest(
    doc_paths: list[str],
    upsert_fn,       # calls upsert_chunks internally
) -> dict:
    state = json.loads(pathlib.Path(STATE_FILE).read_text()) if pathlib.Path(STATE_FILE).exists() else {}
    changed, unchanged = [], []
    for path in doc_paths:
        h = file_hash(path)
        if state.get(path) != h:
            changed.append(path)
            state[path] = h
        else:
            unchanged.append(path)

    for path in changed:
        text   = pathlib.Path(path).read_text(encoding="utf-8", errors="replace")
        chunks = chunk_document(doc_id=path, text=text)
        embeds = embed_texts([c.text for c in chunks])
        upsert_fn(chunks, embeds)

    pathlib.Path(STATE_FILE).write_text(json.dumps(state, indent=2))
    return {"indexed": len(changed), "skipped": len(unchanged)}

from rank_bm25 import BM25Okapi

class HybridKnowledgeBase:
    """Combines BM25 keyword retrieval with vector similarity search."""

    def __init__(self, chunks: list[Chunk], embeddings: list[list[float]]) -> None:
        self.chunks     = chunks
        self.embeddings = embeddings
        tokenised       = [c.text.lower().split() for c in chunks]
        self.bm25       = BM25Okapi(tokenised)

    def bm25_search(self, query: str, top_k: int = 20) -> list[tuple[int, float]]:
        scores = self.bm25.get_scores(query.lower().split())
        ranked = sorted(enumerate(scores), key=lambda x: x[1], reverse=True)
        return ranked[:top_k]

    def vector_search(self, query_vec: list[float], top_k: int = 20) -> list[tuple[int, float]]:
        import math
        def cosine(a, b):
            dot = sum(x*y for x,y in zip(a,b))
            na = math.sqrt(sum(x*x for x in a))
            nb = math.sqrt(sum(x*x for x in b))
            return dot / (na * nb) if na and nb else 0.0
        scored = [(i, cosine(query_vec, e)) for i, e in enumerate(self.embeddings)]
        return sorted(scored, key=lambda x: x[1], reverse=True)[:top_k]

    def rrf_merge(
        self,
        bm25_hits: list[tuple[int, float]],
        vec_hits:  list[tuple[int, float]],
        k: int = 60,
    ) -> list[tuple[int, float]]:
        """Reciprocal Rank Fusion — k=60 is the standard default."""
        scores: dict[int, float] = {}
        for rank, (idx, _) in enumerate(bm25_hits):
            scores[idx] = scores.get(idx, 0.0) + 1 / (k + rank + 1)
        for rank, (idx, _) in enumerate(vec_hits):
            scores[idx] = scores.get(idx, 0.0) + 1 / (k + rank + 1)
        return sorted(scores.items(), key=lambda x: x[1], reverse=True)

    def search(self, query: str, query_vec: list[float], top_k: int = 5) -> list[dict]:
        bm25_hits = self.bm25_search(query, top_k=20)
        vec_hits  = self.vector_search(query_vec, top_k=20)
        merged    = self.rrf_merge(bm25_hits, vec_hits)[:top_k]
        return [
            {"chunk": self.chunks[i], "score": s}
            for i, s in merged
        ]

def recall_at_k(
    queries: list[str],
    relevant_doc_ids: list[list[str]],   # per-query ground-truth
    retrieve_fn,
    k: int = 5,
) -> float:
    hits = 0
    for query, gold_ids in zip(queries, relevant_doc_ids):
        results = retrieve_fn(query, top_k=k)
        retrieved_ids = {r["doc_id"] for r in results}
        if retrieved_ids & set(gold_ids):
            hits += 1
    return hits / len(queries)
